import type { SVGProps } from "react";

export function Logo(props: SVGProps<SVGSVGElement>) {
  return (
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 595 144" {...props}>
      <title>Amironews Logo</title>
      <image href="data:image/png;base64," width="595" height="144" />
    </svg>
  );
}
